// We abuse the public announcements endpoint just to see if the API is alive,
// then call the pageview endpoint to get a rough count.
// Since we can't auth from n8n easily, we track milestones via static data.

const staticData = this.getWorkflowStaticData('global');
const lastMilestone = staticData.lastMilestone || 0;

// For now, this workflow is a template.
// To make it work: add an authenticated call to /api/stats
// or create a public /api/stats/public endpoint.

// Milestone thresholds
const milestones = [10, 25, 50, 100, 250, 500, 1000, 2500, 5000, 10000];

// Placeholder — replace with actual download count
const downloadCount = 0;

const nextMilestone = milestones.find(m => m > lastMilestone && downloadCount >= m);

if (nextMilestone) {
  staticData.lastMilestone = nextMilestone;
  return [{ json: { milestone: nextMilestone, downloads: downloadCount, shouldPost: true } }];
}

return [{ json: { shouldPost: false, downloads: downloadCount, lastMilestone } }];

